#include<bits/stdc++.h>
using namespace std;
long long n,y,s,t,ans;
int main(){
    cin>>n>>y>>s>>t;
    for(int i=1;i<=n;i++){
        bool flag=1;
        for(int j=0;j<s;j++){
            if(fmod((ans-y)/1.0/t,1.0)==0&&(ans-y)/1.0/t>=0){
                flag=0;
            }
            ans++;
        }
        if(flag){
            cout<<"Yes";
            return 0;
        }
    }
    cout<<"No";
}
